// ===== Module 7B — Build PDF HTML Content (consolidated, B&W, 6-page) =====
// Supply page (page 5) is rendered upstream in 'Render Supply Page' and injected via row['_supplyPageHtml'].
function clean(v){return String(v==null?'':v).trim();}
function num(v){const n=Number(String(v==null?'':v).replace(/[^0-9.\-]/g,''));return Number.isFinite(n)?n:null;}
function pnum(v){const n=num(v);return (n!=null&&n>0)?n:null;}
function esc(v){return String(v==null?'':v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
function comma(n){return Number(n).toLocaleString('en-SG');}
function fmtPrice(v){if(!v)return 'n/a';return 'SGD '+comma(Math.round(Number(v)));}
function fmtPsf(v){if(!v)return 'n/a';return 'SGD '+comma(Math.round(Number(v)))+' psf';}
function priceWithPsf(price,psf){if(!price)return 'n/a';return fmtPrice(price)+(psf?' ('+fmtPsf(psf)+')':'');}
function _compSet(raw,ss,sp){var out=[];for(var qi=0;qi<raw.length;qi++){var c=raw[qi];var cpsf=pnum(c['Asking PSF']);if(!cpsf)continue;var inc=clean(c['Include In Analysis']).toUpperCase();if(inc&&inc!=='YES')continue;var st=clean(c['Listing Status']).toUpperCase();if(st&&st!=='ACTIVE')continue;if(clean(c['Own Listing']).toUpperCase()==='YES')continue;var cs=pnum(c['Size']),cp=pnum(c['Asking Price']);if(ss&&sp&&cs===ss&&cp===sp)continue;out.push({project:clean(c['Project Name']),size:cs,price:cp,psf:cpsf,badge:clean(c['Price Badge'])});}out.sort(function(a,b){return a.psf-b.psf;});return out;}

const row=$input.first().json;

const projectName=clean(row['Project Name'])||'Unknown Project';
const blk=clean(row['Blk']);
const street=clean(row['Street Name']);
const level=clean(row['Level']);
const unit=clean(row['Unit']);
const unitRef='#'+String(level).padStart(2,'0')+'-'+String(unit).padStart(2,'0');
const size=pnum(row['Size']);
const sizeStr=size?comma(size)+' sqft':'n/a';
const tenureRaw=clean(row['Tenure']);
const tenureStr=tenureRaw?(/^\d+$/.test(tenureRaw)?tenureRaw+'-yr Leasehold':tenureRaw):'n/a';
const district=clean(row['District']);
const propertyType=clean(row['Property Subtype'])||clean(row['Type'])||'n/a';
const subtypeU=propertyType.toUpperCase();

function pickField(names){for(const n of names){if(n in row){const v=clean(row[n]);if(v!=='')return v;}}return '';}
let bedrooms=clean(row['No. of BR']);
if(!bedrooms){bedrooms=subtypeU.includes('STUDIO')?'Studio':'n/a';}
let bathrooms=pickField(['Bathrooms','No. of Bath','No. of Bathrooms','No. of Baths','Baths','Bathroom']);
if(!bathrooms){bathrooms=subtypeU.includes('STUDIO')?'1':'n/a';}

const planningArea=clean(row['Planning Area']);
const planningRegion=clean(row['Planning Region']);
function titleCase(s){return s.toLowerCase().replace(/\b\w/g,c=>c.toUpperCase());}
const planningAreaDisp=planningArea?titleCase(planningArea):'';
let subjectTopYear=null;
try{const _rcj=clean(row['Radius Comparables JSON']);if(_rcj){const _o=JSON.parse(_rcj);if(_o&&_o.subjectTopYear)subjectTopYear=_o.subjectTopYear;}}catch(e){}
const topSeg=subjectTopYear?('Est. TOP '+subjectTopYear):'';
const headerLineParts=[(blk?blk+' ':'')+street, district, planningAreaDisp, planningRegion, topSeg].filter(Boolean);
const headerLine=headerLineParts.join(' | ');

const generatedAt=new Date().toLocaleDateString('en-SG',{timeZone:'Asia/Singapore',year:'numeric',month:'long',day:'numeric'});

const askPrice=pnum(row['Price']);
const askPsf=pnum(row['PSF']);
const fmvVal=pnum(row['CMA Weighted Value Indication']);
const fmvPsf=pnum(row['CMA Weighted PSF']);
const cmaMinPsf=pnum(row['CMA Min Transacted PSF']);
const cmaMaxPsf=pnum(row['CMA Max Transacted PSF']);

let txRows=[];try{const r=clean(row['CMA Transaction Rows JSON']);if(r)txRows=JSON.parse(r);}catch(e){txRows=[];}
let allTx12m=[];try{const r=clean(row['CMA All Transactions 12M JSON']);if(r)allTx12m=JSON.parse(r);}catch(e){allTx12m=[];}
const usedKey=new Set(txRows.filter(r=>!r.anomaly).map(r=>r.date+'|'+r.price));

function inBand(a){return size&&a&&Math.abs(Number(a)-size)/size<=0.25;}
const bandTx=allTx12m.filter(t=>inBand(t.areaSqft));
const bandPsfs=bandTx.map(t=>Number(t.psf)).filter(p=>p>0).sort((a,b)=>a-b);
const simN=bandPsfs.length||txRows.length;
const rawMinPsf=bandPsfs.length?bandPsfs[0]:cmaMinPsf;
const rawMaxPsf=bandPsfs.length?bandPsfs[bandPsfs.length-1]:cmaMaxPsf;
function median(arr){if(!arr.length)return null;const m=Math.floor(arr.length/2);return arr.length%2?arr[m]:(arr[m-1]+arr[m])/2;}
const subjMedianPsf=median(bandPsfs);
const rawMinPrice=(rawMinPsf&&size)?Math.round(rawMinPsf*size/1000)*1000:null;
const rawMaxPrice=(rawMaxPsf&&size)?Math.round(rawMaxPsf*size/1000)*1000:null;

const _rawComps=Array.isArray(row['_competitorListings'])?row['_competitorListings']:[];
const compList=_compSet(_rawComps,size,askPrice);
const _cPsfs=compList.map(c=>c.psf),_cPrices=compList.map(c=>c.price).filter(p=>p>0);
const compMinPsf=compList.length?compList[0].psf:null;
const compMaxPsf=compList.length?compList[compList.length-1].psf:null;
const compMinPrice=_cPrices.length?Math.min.apply(null,_cPrices):null;
const compMaxPrice=_cPrices.length?Math.max.apply(null,_cPrices):null;
const compIncluded=String(compList.length);
const compTotal=String(compList.length);
const compMedianPsf=_cPsfs.length?median(_cPsfs):null;

const sConservative=pnum(row['Strategy Conservative Price']);
const sBalanced=pnum(row['Strategy Balanced Price']);
const sOptimistic=pnum(row['Strategy Optimistic Price']);
function psfOf(q){return (q&&size)?Math.round(q/size):null;}

const nearMrt=clean(row['Nearest MRT/LRT']);
const nearMrtDist=pnum(row['Nearest MRT/LRT Distance Metres']);
const nearSch=clean(row['Nearest Primary School']);
const nearSchDist=pnum(row['Nearest Primary School Distance Metres']);
const nearbySupermarkets=clean(row['Nearby Supermarkets Within 1KM']);
function fmtDist(m){return m?'~'+comma(m)+' m':'';}
function amenityVal(n,d){if(!n)return 'n/a';const x=fmtDist(d);return esc(n)+(x?' ('+x+')':'');}

const mrtsWithin1km=clean(row['MRTs Within 1KM']);
const schoolsWithin1km=clean(row['Primary Schools Within 1KM']);
const schools1to2km=clean(row['Primary Schools 1-2KM']);
function distOf(part){const i=part.indexOf('approx.');if(i<0)return null;const m=part.slice(i+7).match(/[0-9]+/);return m?Number(m[0]):null;}
function annotateBand(s){const str=clean(s);if(!str)return '';return str.split(';').map(function(part){const p=part.trim();if(!p)return p;const d=distOf(p);if(d!==null&&d>=900&&d<=1100)return p+' *';return p;}).filter(Boolean).join('; ');}
function numberedList(s){const str=clean(s);if(!str)return '';const parts=str.split(';').map(function(x){return x.trim();}).filter(Boolean);const out=[];let n=0;for(const p of parts){if(p.charAt(0)==='+')continue;let e=p.split('approx. ').join('~');e=e.split(' Station (').join(' (');n++;out.push(n+') '+e);}return out.join(', ');}

function row2(l1,v1,l2,v2){return '<tr><td class="lbl">'+l1+'</td><td class="val">'+v1+'</td><td class="lbl">'+l2+'</td><td class="val">'+v2+'</td></tr>';}
function row1(l,v){return '<tr><td class="lbl">'+l+'</td><td class="val" colspan="3">'+v+'</td></tr>';}
function sec(title,content){return '<div class="section"><div class="section-title">'+title+'</div>'+content+'</div>';}
function planHdr(label){return '<div class="header"><div class="header-title">'+label+' &mdash; '+esc(projectName)+' '+unitRef+'</div><div class="header-meta">Generated: '+generatedAt+' | Internal Use Only | Clarity V2 Module 7B</div></div>';}

const subjectTbl='<table class="dt">'+
  row2('Type',esc(propertyType),'Size',sizeStr)+
  row2('Tenure',esc(tenureStr),'Unit',unitRef)+
  row2('Bedrooms',esc(bedrooms),'Bathrooms',esc(bathrooms))+
'</table>';

const locationBlock=(function(){
  const schools1A=annotateBand(schoolsWithin1km);
  const schools12A=annotateBand(schools1to2km);
  const boundaryFlag=(schools1A+' '+schools12A).indexOf(' *')>=0;
  const mrtDisplay=mrtsWithin1km?esc(numberedList(mrtsWithin1km)):(nearMrt?amenityVal(nearMrt,nearMrtDist):'n/a');
  const hasLoc=mrtsWithin1km||schools1A||schools12A||nearbySupermarkets||nearMrt||nearSch;
  if(!hasLoc)return '';
  return '<div class="subhead">Location &amp; Connectivity</div><table class="dt">'+
    row1('MRT / LRT (within 1 km)',mrtDisplay)+
    row1('Primary schools (within 1 km)',schools1A?esc(numberedList(schools1A)):'None within 1 km')+
    row1('Primary schools (1-2 km)',schools12A?esc(numberedList(schools12A)):'None within 1-2 km')+
    row1('Supermarkets (within 1 km)',nearbySupermarkets?esc(numberedList(nearbySupermarkets)):'n/a')+
    '</table><p class="amenity-note">Straight-line distances (not walking).'+(boundaryFlag?' &nbsp;* Within ~100 m of the 1 km mark - verify exact home-school distance via OneMap SchoolQuery before relying on the priority band.':'')+'</p>';
})();

const fmrMonthly=pnum(row['Rental FMR Monthly']);
const fmrPsf=pnum(row['Rental FMR PSF (approx)']);
const ryFmv=pnum(row['Gross Yield on FMV %']);
const ryAsk=pnum(row['Gross Yield on Asking %']);
let rentLine='';
if(fmrMonthly){
  const rentRound=Math.round(fmrMonthly/100)*100;
  const psfStr=fmrPsf?' (~SGD '+fmrPsf.toFixed(2)+' psf, approx.)':'';
  const yF=ryFmv?'~'+(Math.round(ryFmv*10)/10).toFixed(1)+'% FMV':'';
  const yA=ryAsk?'~'+(Math.round(ryAsk*10)/10).toFixed(1)+'% asking':'';
  const yld=(yF||yA)?(' &nbsp;|&nbsp; <strong>Gross yield:</strong> '+[yF,yA].filter(Boolean).join(' / ')):'';
  rentLine='<strong>Indicative rent:</strong> ~SGD '+comma(rentRound)+'/mo'+psfStr+yld;
}

let fmvBlock='';
if(fmvVal&&askPrice){
  const diff=((askPrice-fmvVal)/fmvVal)*100;
  const sgn=diff>=0?'+':'';
  fmvBlock='<div class="fmv-row"><div><strong>Fair Market Value:</strong> '+priceWithPsf(fmvVal,fmvPsf)+
    ' &nbsp;|&nbsp; <strong>Asking:</strong> '+priceWithPsf(askPrice,askPsf)+
    ' &nbsp;|&nbsp; <strong>Difference:</strong> <strong>'+sgn+diff.toFixed(1)+'%</strong></div>'+
    (rentLine?'<div style="margin-top:5px">'+rentLine+'</div>':'')+'</div>';
}else if(rentLine){
  fmvBlock='<div class="fmv-row">'+rentLine+'</div>';
}

let graphSection='';
if(rawMinPsf&&rawMaxPsf){
  const vals=[rawMinPsf,rawMaxPsf];
  if(compMinPsf)vals.push(compMinPsf);
  if(compMaxPsf)vals.push(compMaxPsf);
  if(askPsf)vals.push(askPsf);
  if(fmvPsf)vals.push(fmvPsf);
  const scaleMin=Math.floor(Math.min(...vals)*0.94/100)*100;
  const scaleMax=Math.ceil(Math.max(...vals)*1.06/100)*100;
  const sr=(scaleMax-scaleMin)||1;
  const svgW=540,barH=30,labelW=150,chartW=svgW-labelW-34,rowGap=40;
  const rows=[{label:'Transacted',min:rawMinPsf,max:rawMaxPsf,fill:'#cfcfcf',n:simN}];
  if(compMinPsf&&compMaxPsf)rows.push({label:'Asking Range',min:compMinPsf,max:compMaxPsf,fill:'url(#hatch)',n:compIncluded});
  const toX=psf=>labelW+((psf-scaleMin)/sr)*chartW;
  const yTop=30,barTop=i=>yTop+i*(barH+rowGap);
  const lastBottom=barTop(rows.length-1)+barH,lineTop=yTop-6,lineBottom=lastBottom+6,svgH=lineBottom+52;
  let bars='';
  rows.forEach((r,i)=>{const y=barTop(i),x1=toX(r.min),x2=toX(r.max),bw=Math.max(x2-x1,2);
    bars+='<text x="'+(labelW-12)+'" y="'+(y+barH/2-1)+'" text-anchor="end" font-size="12" fill="#000" font-weight="700">'+r.label+'</text>';
    if(r.n)bars+='<text x="'+(labelW-12)+'" y="'+(y+barH/2+13)+'" text-anchor="end" font-size="9" fill="#666">n='+r.n+'</text>';
    bars+='<rect x="'+x1+'" y="'+y+'" width="'+bw+'" height="'+barH+'" rx="2" fill="'+r.fill+'" stroke="#000" stroke-width="1"/>';
    bars+='<text x="'+(x1-5)+'" y="'+(y+barH/2+4)+'" text-anchor="end" font-size="10" fill="#000">'+comma(Math.round(r.min))+'</text>';
    bars+='<text x="'+(x2+5)+'" y="'+(y+barH/2+4)+'" text-anchor="start" font-size="10" fill="#000">'+comma(Math.round(r.max))+'</text>';
  });
  let overlap='';
  if(rows.length>=2){const oMin=Math.max(rows[0].min,rows[1].min),oMax=Math.min(rows[0].max,rows[1].max);
    if(oMax>oMin){[oMin,oMax].forEach(v=>{const vx=toX(v);
      overlap+='<line x1="'+vx+'" y1="'+lineTop+'" x2="'+vx+'" y2="'+lineBottom+'" stroke="#888" stroke-width="1" stroke-dasharray="2,2"/>';
      overlap+='<text x="'+vx+'" y="'+(lineTop-3)+'" text-anchor="middle" font-size="9" fill="#888">'+comma(Math.round(v))+'</text>';});}}
  let askMark='';
  if(askPsf&&askPsf>=scaleMin&&askPsf<=scaleMax){const ax=toX(askPsf);
    askMark='<line x1="'+ax+'" y1="'+lineTop+'" x2="'+ax+'" y2="'+lineBottom+'" stroke="#000" stroke-width="1.6" stroke-dasharray="6,3"/>';
    askMark+='<text x="'+ax+'" y="'+(lineBottom+15)+'" text-anchor="middle" font-size="9" fill="#000" font-weight="700">Asking '+comma(Math.round(askPsf))+'</text>';}
  let fmvMark='';
  if(fmvPsf&&fmvPsf>=scaleMin&&fmvPsf<=scaleMax){const fx=toX(fmvPsf);
    fmvMark='<line x1="'+fx+'" y1="'+lineTop+'" x2="'+fx+'" y2="'+lineBottom+'" stroke="#000" stroke-width="1.8"/>';
    fmvMark+='<text x="'+fx+'" y="'+(lineBottom+28)+'" text-anchor="middle" font-size="9" fill="#000" font-weight="700">FMV '+comma(Math.round(fmvPsf))+'</text>';}
  const axisCap='<text x="'+(labelW+chartW/2)+'" y="'+(svgH-4)+'" text-anchor="middle" font-size="10" fill="#444">PSF (SGD/sqft)</text>';
  const defs='<defs><pattern id="hatch" width="6" height="6" patternUnits="userSpaceOnUse" patternTransform="rotate(45)"><rect width="6" height="6" fill="#fff"/><line x1="0" y1="0" x2="0" y2="6" stroke="#000" stroke-width="1"/></pattern></defs>';
  const svg='<svg xmlns="http://www.w3.org/2000/svg" width="'+svgW+'" height="'+svgH+'" style="font-family:Arial,sans-serif">'+defs+overlap+bars+askMark+fmvMark+axisCap+'</svg>';
  graphSection=sec('TRANSACTED vs ACTIVE ASKING RANGE','<div class="graph-wrap">'+svg+
    '<p class="graph-note">Transacted = raw studio range (similar size, &plusmn;25%, trailing 12 months). Asking Range = active studio listings. Solid line = FMV. Dashed line = asking. Dotted = overlap. n = sample size.</p></div>');
}

const evidenceTbl='<table class="dt">'+
  row2('Similar-size Sales',String(simN),'Window','Trailing 12 months')+
  row2('Min Transacted',priceWithPsf(rawMinPrice,rawMinPsf),'Max Transacted',priceWithPsf(rawMaxPrice,rawMaxPsf))+
'</table><p class="amenity-note">Raw min&ndash;max of similar-size (studio, &plusmn;25%) URA sales; price restated at subject size ('+sizeStr+').</p>';

const askingTbl='<table class="dt">'+
  row2('Included Listings',compIncluded||'n/a','Total Listings',compTotal||'n/a')+
  row2('Min Asking',priceWithPsf(compMinPrice,compMinPsf),'Max Asking',priceWithPsf(compMaxPrice,compMaxPsf))+
'</table>';

let pricingTbl='';
if(sConservative||sBalanced||sOptimistic){
  function pcell(q){return fmtPrice(q)+(psfOf(q)?'<div class="psf-sub">('+comma(psfOf(q))+' psf)</div>':'');}
  const _premPct=(askPrice&&fmvVal)?(((askPrice-fmvVal)/fmvVal)*100):null;
  const opReco='<div class="fmv-row" style="margin-top:8px;line-height:1.7">'+
    '<div><strong>Operational read:</strong></div>'+
    '<div>&mdash; <strong>Lead list price:</strong> '+fmtPrice(sBalanced)+' (Balanced) &mdash; positioned to attract serious buyers.</div>'+
    '<div>&mdash; <strong>Floor / priced-to-move:</strong> '+fmtPrice(sConservative)+' (at FMV).</div>'+
    '<div>&mdash; <strong>Market-test ceiling:</strong> '+fmtPrice(sOptimistic)+' &mdash; only with a 2&ndash;3 week review; step toward Balanced if no traction.</div>'+
    '<div>&mdash; <strong>Avoid:</strong> '+fmtPrice(askPrice)+' (current asking'+(_premPct!=null?', +'+_premPct.toFixed(1)+'% over FMV':'')+') unless a clear unit-specific premium &mdash; expect extended days-on-market.</div>'+
    '</div>';
  pricingTbl='<table class="dt"><tr>'+
    '<td class="lbl">Conservative</td><td class="val">'+pcell(sConservative)+'</td>'+
    '<td class="lbl">Balanced</td><td class="val">'+pcell(sBalanced)+'</td>'+
    '<td class="lbl">Optimistic</td><td class="val">'+pcell(sOptimistic)+'</td></tr></table>'+
    opReco+
    '<p class="amenity-note">Conservative = priced to move; Balanced = midpoint; Optimistic = an optimistic asking test, not a proven closing ceiling. <b>These are asking / listing strategies, not predicted closing prices:</b> FMV is the valuation anchor (most-probable value); a Balanced ask is set above FMV to leave negotiating room. See the Pricing Advisor page for the full recommendation.</p>';
}

const disclaimer='<div class="disclaimer">Internal agent reference only. Not for client distribution. Pricing is indicative and subject to market conditions, seller motivation, unit condition, and agent review. CMA: URA Private Residential Property Transactions. Competitor data: PropertyGuru snapshot. PSF figures are computed on exact URA floor area (sqm basis); displayed sqft and the rounded monthly rent are for presentation, so a figure may not divide exactly. Clarity V2 Module 7B. See the final page for methodology &amp; formulas.</div>';

const LOGOIMG='<img class="brand-logo" alt="Clarity" src="data:image/png;base64,">';
const page1Header='<div class="header">'+LOGOIMG+'<div class="header-title">Agent Market Brief &mdash; '+esc(projectName)+' '+unitRef+'</div><div class="header-sub">'+esc(headerLine)+'</div><div class="header-meta">Generated: '+generatedAt+' | Internal Use Only | Clarity V2 Module 7B</div></div>';

let trendSection='';
let trend=null;try{const r=clean(row['CMA Trend 12M Rolling JSON']);if(r)trend=JSON.parse(r);}catch(e){trend=null;}
if(trend&&Array.isArray(trend.series)&&trend.series.length){
  const S=trend.series,D=[];
  const W=644,H=230,padL=46,padR=12,padT=10,padB=44,plotW=W-padL-padR,plotH=H-padT-padB;
  const meds=S.map(p=>p.median),dvals=D.map(p=>p.median);const salePts=Array.isArray(trend.sales)?trend.sales.filter(s=>s&&Number.isFinite(s.psf)):[];const allv=meds.concat(dvals).concat(salePts.map(s=>s.psf));
  let ymin=Math.min(...allv),ymax=Math.max(...allv);const span=(ymax-ymin)||100;ymin-=span*0.12;ymax+=span*0.12;
  const n=S.length,X=i=>padL+(n<=1?plotW/2:(i/(n-1))*plotW),Y=v=>padT+(1-(v-ymin)/((ymax-ymin)||1))*plotH;
  const maxc=Math.max(...S.map(p=>p.count||0),1),LOW=4,dMap={};D.forEach(p=>{dMap[p.period]=p.median;});
  let bars='',spts=[],dpts=[],marks='',xlabels='';const step=Math.max(1,Math.ceil(n/6));
  S.forEach((p,i)=>{const x=X(i),bh=((p.count||0)/maxc)*30;
    bars+='<rect x="'+(x-3).toFixed(1)+'" y="'+(padT+plotH-bh).toFixed(1)+'" width="6" height="'+bh.toFixed(1)+'" fill="#e2e2e2" stroke="#cfcfcf" stroke-width="0.5"/>';
    const y=Y(p.median);spts.push(x.toFixed(1)+','+y.toFixed(1));const thin=(p.count||0)<LOW;
    marks+=thin?'<circle cx="'+x.toFixed(1)+'" cy="'+y.toFixed(1)+'" r="3.3" fill="#fff" stroke="#000" stroke-width="1.4"/>':'<circle cx="'+x.toFixed(1)+'" cy="'+y.toFixed(1)+'" r="2.5" fill="#000"/>';
    if(dMap[p.period]!=null)dpts.push(x.toFixed(1)+','+Y(dMap[p.period]).toFixed(1));
    if(i%step===0||i===n-1)xlabels+='<text x="'+x.toFixed(1)+'" y="'+(H-26)+'" font-size="8" fill="#888" text-anchor="middle">'+esc(p.period)+'</text>';});
  function _pd(p){const m=String(p).match(/^(\d{4})-(\d{2})/);return m?new Date(+m[1],+m[2]-1,1):null;}
  function _mo(a,b){const da=_pd(a),db=_pd(b);if(!da||!db)return -1;return (da.getFullYear()-db.getFullYear())*12+(da.getMonth()-db.getMonth());}
  const _p0=S[0].period;let saleDots='',_out=null;
  salePts.forEach(s=>{const off=_mo(s.p,_p0);if(off<0||off>(n-1))return;const x=X(off),y=Y(s.psf);saleDots+='<circle cx="'+x.toFixed(1)+'" cy="'+y.toFixed(1)+'" r="2.4" fill="none" stroke="#777" stroke-width="1"/>';if(!_out||s.psf>_out.psf)_out={psf:s.psf,x,y};});
  let outAnn='';if(_out&&_out.psf>=ymax-(ymax-ymin)*0.18){outAnn='<circle cx="'+_out.x.toFixed(1)+'" cy="'+_out.y.toFixed(1)+'" r="3" fill="#000"/><text x="'+_out.x.toFixed(1)+'" y="'+(_out.y-7).toFixed(1)+'" font-size="8" fill="#000" text-anchor="middle">'+comma(_out.psf)+' (high outlier)</text>';}
  let yticks='';for(let k=0;k<=3;k++){const v=ymin+(k/3)*(ymax-ymin),y=Y(v);
    yticks+='<line x1="'+padL+'" y1="'+y.toFixed(1)+'" x2="'+(W-padR)+'" y2="'+y.toFixed(1)+'" stroke="#eee"/><text x="'+(padL-6)+'" y="'+(y+3).toFixed(1)+'" font-size="8" fill="#888" text-anchor="end">'+comma(Math.round(v))+'</text>';}
  const distLine=dpts.length?'<polyline points="'+dpts.join(' ')+'" fill="none" stroke="#888" stroke-width="1.4" stroke-dasharray="5 3"/>':'';
